/// <summary>
/// The entry point for the controller class.
/// </summary>
/// <param name="_args">The arguments passed from the menu item.</param>
public static void main(Args _args)
{
    ETG_ContractTrackingController controller = new ETG_ContractTrackingController();
    controller.parmArgs(_args);

    // Determine the current legal entity (convert to uppercase to ensure safe comparison)
    //str currentCompany = strUpr(curExt());

    // Choose the design based on the legal entity
    if (curExt() == 'P031' || curExt() == 'P032')
    {
        controller.parmReportName(ssrsReportStr(ETGContractTrackingReport, PrecisionDesign2));
    }
    else
    {
        controller.parmReportName(ssrsReportStr(ETGContractTrackingReport, PrecisionDesign1));
    }


    controller.startOperation();
}
